  ('disabled-6f0ba476-moex-00507', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '近年來空氣污染日益嚴重，政府因而鼓勵民眾騎乘電動機車。然而電動機 車之供給與需求函數分別為Q=10P－75與Q=70－10P（其中價量之單位 分別為萬元與萬輛）。經專家評估最佳的電動機車數目為 10 萬輛，因此 政府應補貼供給者每輛多少元方能達到此一目標？', '["1.5萬元", "2萬元", "2.5萬元", "3萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
