  ('disabled-6f0ba476-moex-00509', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '若市場需求函數為P=100－Q，邊際成本函數為MC=10，則獨占廠商極大 化利潤下，下列敘述何者正確？', '["產量為50", "邊際收益為25", "總成本為450", "利潤為0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
